#!/usr/bin/env node
/**
 * eval-questions.js — Evaluate CFA question quality generated by Claude Haiku
 *
 * Usage:
 *   ANTHROPIC_API_KEY=sk-ant-... node eval-questions.js
 *   ANTHROPIC_API_KEY=sk-ant-... node eval-questions.js --topics Ethics,Derivatives --n 5 --difficulty Hard --level 1
 *   ANTHROPIC_API_KEY=sk-ant-... node eval-questions.js --out report.json
 *
 * Each question is generated then judged by a second Haiku call on 4 criteria:
 *   wellFormed · answerDefensible · explanationAccurate · distractorsPlausible
 * Score = 0–4. Pass threshold: 3+.
 *
 * Use before/after prompt changes as a regression gate. Blocked deploy if
 * overall pass rate drops below --threshold (default 0.80 = 80%).
 */

const {execSync} = require('child_process');
const fs = require('fs');
const https = require('https');

// ── CLI args ─────────────────────────────────────────────────────────────────
const args = process.argv.slice(2);
const flag = (name, def) => {
  const i = args.indexOf(name);
  return i >= 0 ? args[i + 1] : def;
};

const TOPICS_RAW  = flag('--topics', null);
const N           = parseInt(flag('--n', '5'), 10);
const DIFFICULTY  = flag('--difficulty', 'Medium');
const LEVEL       = flag('--level', '1');
const OUT_FILE    = flag('--out', null);
const THRESHOLD   = parseFloat(flag('--threshold', '0.80'));
const JUDGE_MODEL = flag('--judge', 'claude-haiku-4-5-20251001');
const GEN_MODEL   = flag('--gen-model', 'claude-haiku-4-5-20251001');

const TOPICS_L1 = [
  "Ethics",
  "Quantitative Methods",
  "Economics",
  "Financial Statement Analysis",
  "Corporate Issuers",
  "Equity Investments",
  "Fixed Income",
  "Derivatives",
  "Alternative Investments",
  "Portfolio Management",
];

const TOPICS = TOPICS_RAW ? TOPICS_RAW.split(',').map(s => s.trim()) : TOPICS_L1;

const apiKey = process.env.ANTHROPIC_API_KEY;
if (!apiKey) {
  console.error('❌ ANTHROPIC_API_KEY not set.');
  process.exit(1);
}

// ── Prompts ───────────────────────────────────────────────────────────────────
function genPrompt(topic, difficulty, level) {
  const diff = difficulty === 'Easy'
    ? 'recall/definition — one-step, no numbers required'
    : difficulty === 'Medium'
    ? 'apply a formula or concept to a scenario with specific numbers'
    : 'multi-step analysis, nuanced judgment, or reconcile conflicting data';

  return `CFA Level ${level} question generator. Topic: ${topic} | Difficulty: ${difficulty} | Generate: ${N} questions.

Difficulty guidance: ${diff}.
${level === '2' ? 'L2 format: every question must open with a 2–3 sentence mini-vignette/scenario.' : ''}
${level === '3' ? 'L3 format: every question must involve a portfolio management decision — client objectives, IPS constraints, or asset allocation.' : ''}

Return ONLY a JSON array, no markdown:
[{"id":1,"question":"...","options":{"A":"...","B":"...","C":"..."},"answer":"A","explanation":"...","concept":"3-5 word tag","los_tested":"LOS statement"}]

Rules:
- 3 options only (A, B, C). Each wrong option must exploit a real CFA misconception.
- Explanation MUST begin with "Correct: A." (or B or C).
- For numerical questions: compute the EXACT answer first, then include it verbatim as an option. Never use "approximately" or "closest to".
- Wrong options must use recognisable formula errors (wrong rate, wrong sign, missing step).`;
}

function judgePrompt(q) {
  const opts = Object.entries(q.options || {}).map(([k, v]) => `${k}) ${v}`).join('\n');
  return `You are a strict CFA exam quality auditor for CFA Level ${LEVEL}.

Evaluate this multiple-choice question:

QUESTION: ${q.question}
OPTIONS:
${opts}
ANSWER KEY: ${q.answer}
EXPLANATION: ${q.explanation}
LOS TESTED: ${q.los_tested || 'N/A'}

Rate on 4 criteria. Respond with ONLY a JSON object — no markdown:
{
  "wellFormed": true/false,
  "answerDefensible": true/false,
  "explanationAccurate": true/false,
  "distractorsPlausible": true/false,
  "notes": "one sentence — main issue if any, or 'Looks good'"
}

Criteria:
1. wellFormed: Question is clear, grammatically correct, unambiguous, and tests a real CFA concept.
2. answerDefensible: Exactly one answer is clearly correct and the others are wrong for the stated reason.
3. explanationAccurate: The explanation is factually correct for CFA Level ${LEVEL} curriculum. Check any formula or calculation.
4. distractorsPlausible: Wrong options represent realistic exam traps (not obviously wrong, exploit real misconceptions).`;
}

// ── API call ──────────────────────────────────────────────────────────────────
function callAPI(prompt, model, maxTokens = 1200) {
  const body = JSON.stringify({
    model,
    max_tokens: maxTokens,
    messages: [{ role: 'user', content: prompt }],
  });

  const proxy = process.env.HTTPS_PROXY || process.env.https_proxy;
  const options = {
    hostname: 'api.anthropic.com',
    path: '/v1/messages',
    method: 'POST',
    headers: {
      'x-api-key': apiKey,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json',
      'content-length': Buffer.byteLength(body),
    },
  };
  if (proxy) {
    try {
      const { URL } = require('url');
      const u = new URL(proxy);
      options.hostname = u.hostname;
      options.port = u.port || 443;
      options.path = 'https://api.anthropic.com/v1/messages';
      options.headers['host'] = 'api.anthropic.com';
    } catch {}
  }

  return new Promise((resolve, reject) => {
    const req = https.request(options, res => {
      let data = '';
      res.on('data', c => (data += c));
      res.on('end', () => {
        try {
          const parsed = JSON.parse(data);
          if (parsed.error) return reject(new Error(parsed.error.message));
          const text = (parsed.content?.[0]?.text || '').replace(/```json\n?|```/g, '').trim();
          resolve(text);
        } catch (e) {
          reject(new Error(`Parse failed: ${e.message}\nRaw: ${data.slice(0, 300)}`));
        }
      });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

// ── Main ──────────────────────────────────────────────────────────────────────
async function run() {
  console.log(`\nClearCFA Question Quality Eval`);
  console.log(`  Topics: ${TOPICS.join(', ')}`);
  console.log(`  N per topic: ${N} | Difficulty: ${DIFFICULTY} | Level: ${LEVEL}`);
  console.log(`  Gen model: ${GEN_MODEL} | Judge model: ${JUDGE_MODEL}`);
  console.log(`  Pass threshold: ${Math.round(THRESHOLD * 100)}%`);
  console.log('');

  const results = [];
  let totalGenerated = 0;
  let totalPassed = 0;

  for (const topic of TOPICS) {
    process.stdout.write(`  ${topic.padEnd(32, '.')} `);

    // 1. Generate questions
    let questions = [];
    try {
      const raw = await callAPI(genPrompt(topic, DIFFICULTY, LEVEL), GEN_MODEL, 2000);
      questions = JSON.parse(raw);
      if (!Array.isArray(questions)) throw new Error('Not an array');
    } catch (e) {
      console.log(`❌ GEN FAILED: ${e.message.slice(0, 80)}`);
      results.push({ topic, error: 'generation_failed', questions: [] });
      continue;
    }

    // 2. Judge each question
    const judged = [];
    for (const q of questions.slice(0, N)) {
      let verdict = null;
      try {
        const raw = await callAPI(judgePrompt(q), JUDGE_MODEL, 400);
        verdict = JSON.parse(raw);
      } catch (e) {
        verdict = { wellFormed: false, answerDefensible: false, explanationAccurate: false, distractorsPlausible: false, notes: `Judge failed: ${e.message.slice(0, 60)}` };
      }
      const score = ['wellFormed', 'answerDefensible', 'explanationAccurate', 'distractorsPlausible']
        .filter(k => verdict[k] === true).length;
      const pass = score >= 3;
      judged.push({ q, verdict, score, pass });
      if (pass) totalPassed++;
      totalGenerated++;
    }

    const topicPass = judged.filter(j => j.pass).length;
    const topicTotal = judged.length;
    const rate = topicTotal > 0 ? topicPass / topicTotal : 0;
    const bar = `[${'█'.repeat(Math.round(rate * 10))}${'░'.repeat(10 - Math.round(rate * 10))}]`;
    console.log(`${bar} ${topicPass}/${topicTotal} pass (${Math.round(rate * 100)}%)`);

    results.push({ topic, passRate: rate, passed: topicPass, total: topicTotal, questions: judged });
  }

  // ── Summary ────────────────────────────────────────────────────────────────
  const overallRate = totalGenerated > 0 ? totalPassed / totalGenerated : 0;
  const verdict = overallRate >= THRESHOLD ? 'PASS' : 'FAIL';

  console.log('');
  console.log('══════════════════════════════════════════════');
  console.log(`  Overall: ${totalPassed}/${totalGenerated} questions pass (${Math.round(overallRate * 100)}%)`);
  console.log(`  Threshold: ${Math.round(THRESHOLD * 100)}%`);
  console.log(`  Verdict: ${verdict === 'PASS' ? '✅ PASS' : '❌ FAIL'}`);
  console.log('══════════════════════════════════════════════');

  // Failures detail
  const failures = results.flatMap(r => (r.questions || []).filter(j => !j.pass));
  if (failures.length > 0) {
    console.log(`\n  Failed questions (${failures.length}):`);
    failures.slice(0, 10).forEach(({ q, verdict: v, score }) => {
      const failed = ['wellFormed', 'answerDefensible', 'explanationAccurate', 'distractorsPlausible']
        .filter(k => v[k] !== true).join(', ');
      console.log(`    ✗ [${score}/4] "${(q.question || '').slice(0, 60)}…"`);
      console.log(`      Failed: ${failed}`);
      console.log(`      Note: ${v.notes || ''}`);
    });
    if (failures.length > 10) console.log(`    … and ${failures.length - 10} more`);
  }

  // ── Output file ────────────────────────────────────────────────────────────
  if (OUT_FILE) {
    const report = {
      generatedAt: new Date().toISOString(),
      config: { topics: TOPICS, n: N, difficulty: DIFFICULTY, level: LEVEL, threshold: THRESHOLD },
      overall: { passRate: overallRate, passed: totalPassed, total: totalGenerated, verdict },
      byTopic: results.map(r => ({
        topic: r.topic,
        passRate: r.passRate,
        passed: r.passed,
        total: r.total,
        error: r.error,
        questions: (r.questions || []).map(j => ({
          question: j.q?.question?.slice(0, 120),
          answer: j.q?.answer,
          score: j.score,
          pass: j.pass,
          verdict: j.verdict,
        })),
      })),
    };
    fs.writeFileSync(OUT_FILE, JSON.stringify(report, null, 2));
    console.log(`\n  Report saved: ${OUT_FILE}`);
  }

  console.log('');
  process.exit(verdict === 'PASS' ? 0 : 1);
}

run().catch(e => {
  console.error('Fatal:', e.message);
  process.exit(1);
});
